parameters.jsCode:
// 從未聯絡名單中，挑出「搶到時間 + 7 天」剩 <= 2 天（含當天、含已過期）的
// 剩 2/1 天、今天 = 黃燈🟡；已過期 = 紅燈🔴。沒有符合的就回空陣列 → 不推 LINE。
const USER_ID = 'Ufab42c56b2eb9b9a9ff18c367b85a6dd'; // 薛力瑜
const DAY = 24 * 3600 * 1000;
const results = $input.first().json.results || [];
const now = new Date();

const rows = [];
for (const p of results) {
  const props = p.properties || {};
  const grab = props['搶到時間'] && props['搶到時間'].date && props['搶到時間'].date.start;
  if (!grab) continue; // 沒搶到時間不算
  const deadline = new Date(new Date(grab).getTime() + 7 * DAY);
  const daysLeft = Math.trunc((deadline - now) / DAY); // 與 Notion dateBetween 一致（截斷）
  if (daysLeft > 1) continue; // 以 Notion「🔔 待聯絡」view 為準：只推剩≤1天(含今天/過期)
  const name = (props['姓名'] && props['姓名'].title && props['姓名'].title[0] && props['姓名'].title[0].plain_text) || '(未命名)';
  const phone = (props['電話'] && props['電話'].phone_number) || '';
  const city = (props['縣市'] && props['縣市'].select && props['縣市'].select.name) || '';
  const cat = (props['類型'] && props['類型'].select && props['類型'].select.name) || '';
  const acct = (props['帳號'] && props['帳號'].select && props['帳號'].select.name) || '';
  let flag;
  if (daysLeft < 0) flag = '🔴已過期';
  else if (daysLeft === 0) flag = '🟡今天到期';
  else flag = '🟡剩' + daysLeft + '天';
  rows.push({ daysLeft, name, phone, city, cat, acct, flag });
}

if (rows.length === 0) return []; // 沒有待提醒 → 不推 LINE

rows.sort((a, b) => a.daysLeft - b.daysLeft); // 最急（已過期）排前面
const today = now.toLocaleDateString('zh-TW', { timeZone: 'Asia/Taipei' });
const lines = rows.map(function (r) {
  const parts = [r.name, r.city + r.cat, r.phone, r.acct].filter(Boolean).join('｜');
  return '・' + r.flag + '｜' + parts;
}).join('\n');
const text = '🔔 待聯絡提醒 ' + today + '\n以下 ' + rows.length + ' 筆「未聯絡」快到期，記得跟進：\n\n' + lines;
return [{ json: { userId: USER_ID, text } }];
